const body = $input.first().json.body ?? $input.first().json;
const bookingId = body.booking_id || body.bookingId;
if (!bookingId) {
  throw new Error('booking_id is required');
}
const rawKind = (body.payment_kind || body.paymentKind || 'deposit_only').toString();
const paymentKind = rawKind === 'full_amount' ? 'full_amount' : 'deposit_only';
return [{ json: { booking_id: bookingId, payment_kind: paymentKind } }];

// Uses this.helpers.httpRequest (not fetch/URLSearchParams — unavailable in n8n Code sandbox)
const row = $input.first().json;
const paymentKind = $('Code - Parse Request').first().json.payment_kind;
const defaultDeposit = parseInt($env.STRIPE_DEFAULT_DEPOSIT_CENTS || '20000', 10);

let stripeKey = $env.STRIPE_SECRET_KEY;
if (!stripeKey) {
  try {
    const cred = await this.getCredentials('httpHeaderAuth');
    const v = cred.value || '';
    stripeKey = v.replace(/^Bearer\s+/i, '').trim();
  } catch (e) {}
}
if (!stripeKey) {
  throw new Error('Set STRIPE_SECRET_KEY on the n8n container or attach Stripe API (test) credential');
}

if (!row.booking_id) {
  throw new Error('Booking not found for booking_id');
}

let amountCents;
if (paymentKind === 'full_amount') {
  amountCents = row.total_amount_cents;
  if (!amountCents || Number(amountCents) < 1) {
    throw new Error('full_amount requires bookings.total_amount_cents > 0');
  }
} else {
  const dep = row.deposit_required_cents;
  // 0 is treated as unset (CSV/sync often stores 0 instead of null)
  amountCents = (dep != null && Number(dep) > 0) ? Number(dep) : defaultDeposit;
}

if (!amountCents || amountCents < 1) {
  throw new Error('Checkout amount must be at least 1 cent');
}

const successUrl = $env.STRIPE_CHECKOUT_SUCCESS_URL || 'http://localhost:5678/webhook/stripe-checkout-success?session_id={CHECKOUT_SESSION_ID}';
const cancelUrl = $env.STRIPE_CHECKOUT_CANCEL_URL || 'https://www.wolf-house.com/surfcampsomo';

function enc(key, value) {
  return encodeURIComponent(key) + '=' + encodeURIComponent(String(value));
}

const productName = paymentKind === 'full_amount'
  ? ('Wolfhouse stay — ' + (row.booking_code || row.booking_id))
  : ('Wolfhouse deposit — ' + (row.booking_code || row.booking_id));

const formBody = [
  enc('mode', 'payment'),
  enc('success_url', successUrl),
  enc('cancel_url', cancelUrl),
  enc('client_reference_id', row.booking_id),
  enc('metadata[client_id]', row.client_id),
  enc('metadata[booking_id]', row.booking_id),
  enc('metadata[booking_code]', row.booking_code || ''),
  enc('metadata[payment_kind]', paymentKind),
  enc('line_items[0][quantity]', '1'),
  enc('line_items[0][price_data][currency]', 'eur'),
  enc('line_items[0][price_data][unit_amount]', amountCents),
  enc('line_items[0][price_data][product_data][name]', productName),
].join('&');

const data = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.stripe.com/v1/checkout/sessions',
  headers: {
    Authorization: 'Bearer ' + stripeKey,
    'Content-Type': 'application/x-www-form-urlencoded',
  },
  body: formBody,
});

if (data.error) {
  throw new Error(data.error.message || 'Stripe API error');
}

return [{
  json: {
    ...row,
    payment_kind: paymentKind,
    amount_due_cents: amountCents,
    stripe_checkout_session_id: data.id,
    checkout_url: data.url,
  },
}];

