INSERT INTO payments (
  client_id, booking_id, payment_kind, currency,
  amount_due_cents, amount_paid_cents, status,
  stripe_checkout_session_id, checkout_url, metadata
) VALUES (
  $1::uuid, $2::uuid, $3::payment_kind, 'EUR',
  $4, 0, 'checkout_created',
  $5, $6, jsonb_build_object('stripe_mode', 'payment', 'created_by', 'n8n-create-payment-session')
)
RETURNING id AS payment_id;
